@inject IJSRuntime JS
@implements IAsyncDisposable

<div @ref="_dropZoneRef" class="drop-zone @(_isDragOver ? "drag-over" : "")">
    <p class="drop-zone-text">Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _files)
        {
            <li class="file-entry @(entry.Error is not null ? "file-error" : "")">
                <div class="file-details">
                    @if (entry.Error is not null)
                    {
                        <span class="error-message">@entry.Error</span>
                        <span class="file-name">@entry.Info.Name</span>
                    }
                    else
                    {
                        <span class="file-name">@entry.Info.Name</span>
                        <span class="file-meta">@FormatSize(entry.Info.Size) &middot; @entry.Info.Type</span>
                    }
                </div>
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSizeBytes = 10L * 1024 * 1024;

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private bool _isDragOver;
    private readonly List<FileEntry> _files = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-a1525c0e4ce049eeb8849cf5ee5460de/Components/FileDropZone.razor.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            await _module.InvokeVoidAsync("initDropZone", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnDragOverChanged(bool isOver)
    {
        _isDragOver = isOver;
        StateHasChanged();
        await Task.CompletedTask;
    }

    [JSInvokable]
    public async Task OnFilesDropped(FileData[] droppedFiles)
    {
        _isDragOver = false;

        foreach (var f in droppedFiles)
        {
            var info = new FileInfo(f.Name, f.Size, f.Type);
            string? error = f.Size > MaxFileSizeBytes
                ? $"File exceeds the 10 MB limit ({FormatSize(f.Size)})"
                : null;
            _files.Add(new FileEntry(info, error));
        }

        StateHasChanged();
        await NotifyParent();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private Task NotifyParent()
    {
        var accepted = _files
            .Where(e => e.Error is null)
            .Select(e => e.Info)
            .ToList();
        return OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("disposeDropZone", _dropZoneRef);
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    public record FileInfo(string Name, long Size, string Type);
    private record FileEntry(FileInfo Info, string? Error);
    private record FileData(string Name, long Size, string Type);
}

.drop-zone {
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 160px;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    background-color: #f8f9fa;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

.drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
}

.drop-zone-text {
    color: #6c757d;
    font-size: 1.1rem;
    margin: 0;
    pointer-events: none;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    margin-bottom: 0.5rem;
    background: #fff;
}

.file-entry.file-error {
    border-color: #dc3545;
    background: #fff5f5;
}

.file-details {
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
    min-width: 0;
}

.file-name {
    font-weight: 500;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.file-meta {
    font-size: 0.85rem;
    color: #6c757d;
}

.error-message {
    font-size: 0.85rem;
    color: #dc3545;
    font-weight: 600;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.25rem 0.6rem;
    cursor: pointer;
    flex-shrink: 0;
    margin-left: 1rem;
    font-size: 0.85rem;
    transition: background-color 0.15s, color 0.15s;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

const zones = new Map();

export function initDropZone(element, dotNetRef) {
    function onDragEnter(e) {
        e.preventDefault();
        dotNetRef.invokeMethodAsync('OnDragOverChanged', true);
    }

    function onDragOver(e) {
        e.preventDefault();
    }

    function onDragLeave(e) {
        if (!element.contains(e.relatedTarget)) {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', false);
        }
    }

    function onDrop(e) {
        e.preventDefault();
        const files = Array.from(e.dataTransfer.files).map(f => ({
            name: f.name,
            size: f.size,
            type: f.type || 'application/octet-stream'
        }));
        dotNetRef.invokeMethodAsync('OnFilesDropped', files);
    }

    element.addEventListener('dragenter', onDragEnter);
    element.addEventListener('dragover', onDragOver);
    element.addEventListener('dragleave', onDragLeave);
    element.addEventListener('drop', onDrop);

    zones.set(element, { onDragEnter, onDragOver, onDragLeave, onDrop });
}

export function disposeDropZone(element) {
    const handlers = zones.get(element);
    if (handlers) {
        element.removeEventListener('dragenter', handlers.onDragEnter);
        element.removeEventListener('dragover', handlers.onDragOver);
        element.removeEventListener('dragleave', handlers.onDragLeave);
        element.removeEventListener('drop', handlers.onDrop);
        zones.delete(element);
    }
}

